   259→
   260→            // MemberEpoch - always sent
   261→            data.setMemberEpoch(membershipManager.memberEpoch());
   262→
   263→            // InstanceId - set if present
   264→            membershipManager.groupInstanceId().ifPresent(data::setInstanceId);
   265→
   266→            boolean sendAllFields = membershipManager.state() == MemberState.JOINING;
   267→
   268→            // RebalanceTimeoutMs - only sent when joining or if it has changed since the last heartbeat
   269→            if (sendAllFields || sentFields.rebalanceTimeoutMs != rebalanceTimeoutMs) {
